import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import StarRating from './StarRating';
import Badge from './Badge';
import './ProductCard.css';

export default function ProductCard({ product }) {
  const { addItem, items } = useCart();
  const [added, setAdded]  = useState(false);

  const inCart = items.some(i => i.id === product.id);

  const handleAdd = (e) => {
    e.preventDefault();
    addItem(product);
    setAdded(true);
    setTimeout(() => setAdded(false), 1500);
  };

  return (
    <Link to={`/product/${product.id}`} className="product-card" aria-label={product.title}>
      <div className="product-card__image-wrap">
        <img
          src={product.image}
          alt={product.title}
          className="product-card__image"
          loading="lazy"
        />
        <div className="product-card__overlay" />
        <div className="product-card__quick-view">View Details →</div>
      </div>

      <div className="product-card__body">
        <Badge variant="accent">{product.category}</Badge>
        <h3 className="product-card__title">{product.title}</h3>

        <div className="product-card__rating">
          <StarRating rating={product.rating?.rate} count={product.rating?.count} size="sm" />
        </div>

        <div className="product-card__footer">
          <span className="product-card__price">${product.price.toFixed(2)}</span>
          <button
            className={`product-card__btn ${inCart ? 'product-card__btn--in-cart' : ''} ${added ? 'product-card__btn--added' : ''}`}
            onClick={handleAdd}
            aria-label="Add to cart"
          >
            {added ? (
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                <polyline points="20 6 9 17 4 12" />
              </svg>
            ) : (
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <path d="M6 2L3 6v14a2 2 0 002 2h14a2 2 0 002-2V6l-3-4z"/>
                <line x1="3" y1="6" x2="21" y2="6"/>
                <path d="M16 10a4 4 0 01-8 0"/>
              </svg>
            )}
          </button>
        </div>
      </div>
    </Link>
  );
}
